import{_ as a,o as t,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Overview Page","description":"","frontmatter":{"title":"Overview Page","slug":"branch-summary-page"},"headers":[],"relativePath":"marketer-hub/branch-summary-page.md","filePath":"marketer-hub/branch-summary-page.md"}'),i={name:"marketer-hub/branch-summary-page.md"};function n(s,e,l,h,c,u){return t(),r("div",null,[...e[0]||(e[0]=[o('<div class="info custom-block"><p class="custom-block-title">Attention</p><p>The Overview Summary tab is part of the legacy Branch experience.</p><p>Our new Branch Analysis tool offers customizable dashboards made up of flexible widgets to capture the data you need. Branch Analysis is being rolled out to customers in phases. While you&#39;re waiting for access, discover how to filter, share, and export campaign performance across different channels on our <a href="https://help.branch.io/docs/branch-analysis" target="_blank" rel="noreferrer">Analysis Overview</a> page.</p></div><p>The <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Overview</a> page provides a global overview of your performance across different channels, campaigns, and use cases in the Branch ecosystem. Here, you can quickly view analytics breakdowns for:</p><ul><li>All Data</li><li>Journeys</li><li>Short Links</li><li>Ads</li><li>Email</li></ul><h2 id="report-settings" tabindex="-1">Report Settings <a class="header-anchor" href="#report-settings" aria-label="Permalink to &quot;Report Settings&quot;">​</a></h2><h3 id="date-range" tabindex="-1">Date Range <a class="header-anchor" href="#date-range" aria-label="Permalink to &quot;Date Range&quot;">​</a></h3><p>You can choose the following date ranges for your report:</p><ul><li><p>Last 3 Days</p></li><li><p>Last 7 Days</p></li><li><p>Last 14 Days</p></li><li><p>Last 30 Days</p></li><li><p>Last 90 Days</p></li><li><p>Custom...</p><ul><li>By default, you are only allowed to look back up to 6 months of data.</li></ul></li></ul><p>There are built-in date ranges to choose from or you can have a custom date range selected.</p><h3 id="sharing" tabindex="-1">Sharing <a class="header-anchor" href="#sharing" aria-label="Permalink to &quot;Sharing&quot;">​</a></h3><p>You can easily share the Overview page in its current state - i.e including whatever changes you have made to default view - by clicking on the link button and copying the auto-generated Branch Link. Users who have access to your Branch Dashboard will then be able to see the view you&#39;ve shared.</p><h3 id="saving" tabindex="-1">Saving <a class="header-anchor" href="#saving" aria-label="Permalink to &quot;Saving&quot;">​</a></h3><p>You can also save the Overview page in its current state - i.e including whatever changes you have made to default view - by clicking on the flag button, naming the view, and clicking Save.</p><p>You can also access your previously saved views here as well.</p><h3 id="resetting" tabindex="-1">Resetting <a class="header-anchor" href="#resetting" aria-label="Permalink to &quot;Resetting&quot;">​</a></h3><p>You can reset the Overview page back to its default state at any time, by clicking on the reset button.</p><h2 id="summary-tiles" tabindex="-1">Summary Tiles <a class="header-anchor" href="#summary-tiles" aria-label="Permalink to &quot;Summary Tiles&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">Summary Tiles vs Table Data</p><p>There may be a difference in conversion proportions when comparing the Summary Tiles and the Events/Performance Tables. In the tables, the total unique will differentiate events based on their compare-by dimensions, leading to a greater count compared to the Summary Tiles.</p></div><p>Each summary tile includes the following information:</p><ul><li>Large number represents metric for current time period.</li><li>Small number represents metric for previous time period.</li><li>Arrow to right indicates whether metric has increased or decreased.</li></ul><p>To change which event is shown:</p><ol><li>For the respective tile, click on the Pencil icon.</li><li>In the <strong>Customize Tile</strong> modal, click within the <strong>Show</strong> drop-down.</li><li>From the <strong>Show</strong> drop-down, select the event you want to populate the graph with.</li><li>Click <strong>Save</strong>.</li></ol><p>Each tile can be customized to show one of the following events:</p><details><summary>Available SHOW Events</summary><ul><li><strong>Installs</strong></li><li><strong>Pageviews</strong></li><li><strong>Views</strong></li><li><strong>Clicks</strong></li><li><strong>Opens</strong></li><li><strong>Reinstalls</strong></li><li><strong>Web Session Starts</strong></li><li><strong>Web to App Redirects</strong></li><li><strong>SMS Sent</strong></li><li><strong>Impressions</strong></li><li><strong>Journey Dismissals</strong></li></ul></details><h2 id="summary-charts" tabindex="-1">Summary Charts <a class="header-anchor" href="#summary-charts" aria-label="Permalink to &quot;Summary Charts&quot;">​</a></h2><p>Summary Charts are an easy-to-use way for you to be able to see campaign performance quickly at a high level. It&#39;s a great tool to compare multiple data sources to find valuable insights.</p><h3 id="customization" tabindex="-1">Customization <a class="header-anchor" href="#customization" aria-label="Permalink to &quot;Customization&quot;">​</a></h3><h4 id="show" tabindex="-1">Show <a class="header-anchor" href="#show" aria-label="Permalink to &quot;Show&quot;">​</a></h4><p>You can <strong>Show</strong> 2 values in which your chart will automatically conform to. Here, you&#39;ll be able to add helpful at-a-glance metrics like installs, purchases, etc.</p><div class="info custom-block"><p class="custom-block-title">Data Limits</p><p><strong>Event/Metric Records</strong></p><p>We will load the top 5,000 records for each event or metric. Some low-volume records may be missing from the displayed analytics when looking at many different compare bys. In particular, data sorted by ascending values may be limited.</p><p><strong>Cardinality Protection</strong></p><p>Branch limits all dimensions to 40,000 values per publisher per day. This means that you can only see up to 40,000 unique campaigns, ad names, etc in the Dashboard.</p><p>If an app tries to send up &gt; 40,000 values for a single dimension (e.g. ~campaign) in a day, then Branch stops tracking those unique values. Branch combines additional values together and bucket them under the value &quot;Other&quot;.</p></div><h4 id="compare-by" tabindex="-1">Compare By <a class="header-anchor" href="#compare-by" aria-label="Permalink to &quot;Compare By&quot;">​</a></h4><p>You can add 1 <strong>Compare by</strong> value to break down your data by a specific dimension.</p><h4 id="filter" tabindex="-1">Filter <a class="header-anchor" href="#filter" aria-label="Permalink to &quot;Filter&quot;">​</a></h4><p>You can add 2 <strong>Filters</strong> to get more granular with the data shown in the Summary Chart. Here you can add specific values for keys like os, ad partner, etc.</p><h4 id="organic-unique" tabindex="-1">Organic/Unique <a class="header-anchor" href="#organic-unique" aria-label="Permalink to &quot;Organic/Unique&quot;">​</a></h4><p>When <strong>Unique</strong> is checked, Branch employs an algorithm to generate an approximation of unique users completing an event within a given time period.</p><p>For example: Within the time interval selected, if 1 user clicks 100 times, the dashboard will only display 1 unique click.</p><p>There is no concept of &quot;unique revenue&quot;; &quot;revenue&quot; is always the sum of all purchase events.</p><p>By default, Unique is shown.</p><p>When <strong>Organic</strong> is checked, unattributed data will show (attributed: false). This data is not attributed to any click or impression, and is the same as &quot;organic&quot; or &quot;direct&quot; data. By default, Organics are left hidden.</p><h3 id="views-download" tabindex="-1">Views/Download <a class="header-anchor" href="#views-download" aria-label="Permalink to &quot;Views/Download&quot;">​</a></h3><p>By clicking the button in the upper right hand corner of the chart, you have the ability to <strong>View in Full Screen</strong> or download in one of the following formats:</p><ul><li><strong>PNG</strong></li><li><strong>XLS</strong></li><li><strong>SVG</strong></li><li><strong>CSV</strong></li></ul><h2 id="events-performance-table" tabindex="-1">Events/Performance Table <a class="header-anchor" href="#events-performance-table" aria-label="Permalink to &quot;Events/Performance Table&quot;">​</a></h2><p>For a full guide on customizing the events/performance table, view our guide on <a href="./dashboard-reports.html#eventsperformance-table">Dashboard Reports</a>.</p>',44)])])}const m=a(i,[["render",n]]);export{p as __pageData,m as default};
